## Code Example

```typescript
type TenantKey = string;
interface OpenApiSpec { /* fields omitted */ }

function mapRestToGraphQL(tenant: TenantKey, path: string, method: string, payload: any): { query: string, variables: any } {
  if (method === 'GET' && path.startsWith('/items/')) {
    const id = path.split('/')[2];
    return {
      query: `query GetItem($id: ID!) { item(id: $id) { id name } }`,
      variables: { id }
    };
  }
