Implement the OAuth2 Device Authorization Grant flow with the following components:

**1. Device Authorization Endpoint (/device_authorize)**
The device requests authorization, receiving codes for user verification:
```javascript
// POST /device_authorize
app.post('/device_authorize', async (req, res) => {
  const { client_id, scope } = req.body;

  const device_code = crypto.randomBytes(32).toString('base64url');
  const user_code = generateUserCode(); // 8-char readable code

  await redis.setEx(`device:${device_code}`, 300, JSON.stringify({
    client_id,
    scope: scope.split(' '),
    status: 'pending'
  }));

  res.json({
    device_code,
    user_code,
    verification_uri: `${config.issuer}/device-verify`,
    expires_in: 300,
    interval: 5
  });
});
```

**2. Token Endpoint (/token) - Polling**
The device polls this endpoint until user approval:
```javascript
// POST /token
app.post('/token', async (req, res) => {
  const { grant_type, device_code, client_id } = req.body;

  if (grant_type !== 'urn:ietf:params:oauth:grant-type:device_code') {
    return res.status(400).json({ error: 'invalid_grant' });
  }

  const auth = await redis.get(`device:${device_code}`);
  if (!auth) return res.status(400).json({ error: 'expired_token' });
  const authData = JSON.parse(auth);

  if (authData.status === 'pending') {
    return res.status(400).json({ error: 'authorization_pending' });
  }

  if (authData.status === 'denied') {
    return res.status(400).json({ error: 'access_denied' });
  }

  // User approved - validate OIDC ID token and issue internal JWT
  const idToken = authData.id_token;
  const payload = await validateOIDCToken(idToken, client_id);

  const internalToken = jwt.sign(
    { 
      device_id: payload.sub,
      scopes: authData.scope,
      aud: client_id
    },
    config.internalJwtSecret,
    { expiresIn: '1h' }
  );

  // Store in revocation cache
  await redis.setEx(`revoke:${payload.sub}`, 3600, 'active');

  res.json({ access_token: internalToken, token_type: 'Bearer', expires_in: 3600 });
});
```

**3. OIDC Token Validation with JWKS**
```javascript
async function validateOIDCToken(idToken, expectedAud) {
  const jwks = jose.createRemoteJWKSet(new URL(`${config.issuer}/.well-known/jwks.json`));

  const { payload } = await jose.jwtVerify(idToken, jwks, {
    issuer: config.issuer,
    audience: expectedAud
  });

  // Check revocation cache
  const revoked = await redis.get(`revoke:${payload.sub}`);
  if (revoked) throw new Error('Token revoked');

  return payload;
}
```

**4. Device-Scoped Access Middleware**
```javascript
function requireDeviceScope(requiredScopes = []) {
  return async (req, res, next) => {
    const authHeader = req.headers.authorization;
    if (!authHeader?.startsWith('Bearer ')) {
      return res.status(401).json({ error: 'missing_token' });
    }

    const token = authHeader.slice(7);

    try {
      const decoded = jwt.verify(token, config.internalJwtSecret);

      // Per-device audience check
      if (decoded.aud !== req.body.client_id && decoded.aud !== '*') {
        return res.status(403).json({ error: 'invalid_audience' });
      }

      // Scope validation
      const tokenScopes = new Set(decoded.scopes);
      const hasAllScopes = requiredScopes.every(s => tokenScopes.has(s));

      if (!hasAllScopes) {
        return res.status(403).json({ error: 'insufficient_scope' });
      }

      req.device = { id: decoded.device_id, scopes: decoded.scopes };
      next();
    } catch (err) {
      return res.status(401).json({ error: 'invalid_token' });
    }
  };
}
```

**Usage Example:**
```javascript
app.get('/api/vehicle/status', requireDeviceScope(['read:vehicle']), (req, res) => {
  res.json({ device: req.device.id, status: 'online' });
});
```

