## Code Example

```javascript
// Issue internal token with nonce (Node.js)
const jwt = require('jsonwebtoken');

async function issueInternalToken({ tenant_id, user_id, scopes, nonce }) {
  const payload = {
    tenant_id,
    sub: user_id,
    scopes,
    nonce,
    iat: Math.floor(Date.now() / 1000),
    exp: Math.floor(Date.now() / 1000) + 300 // 5-minute expiry
  };
  return jwt.sign(payload, getInternalSigningKey(tenant_id), { algorithm: 'RS256' });
}

// Validate nonce during token validation
async function validateAndConsumeNonce(tenant_id, nonce) {
  const key = `nonce:${tenant_id}:${nonce}`;
  const exists = await redis.setnx(key, '1');
  if (!exists) {
    throw new Error('Replay detected: nonce already used');
  }
  await redis.expire(key, 300); // Match token TTL
  return true;
}

// /validate endpoint - lightweight claim extraction
app.post('/validate', async (req, res) => {
  const { token } = req.body;
  const [header] = token.split('.');
  const decodedHeader = JSON.parse(Buffer.from(header, 'base64'));
  const tenant_id = decodedHeader.tenant_id;

  const claims = await extractClaimsWithoutFullDecode(token, tenant_id);
  return res.json({ valid: true, claims });
});
```

