**Answer:** The auth proxy accepts OIDC ID tokens or SAML assertions, extracts tenant and user scopes, and issues an internal JWT with the audience (`aud`) scoped to the target downstream service. A per-tenant in-memory TTL replay cache (e.g., 5 minutes) keyed by `jti` prevents token reuse.

```javascript
// Internal JWT issuance
function issueInternalJWT(user, tenant, downstreamService) {
  const now = Math.floor(Date.now() / 1000);
  const payload = {
    sub: user.id,
    iss: 'auth-proxy-internal',
    aud: downstreamService,
    exp: now + 3600,
    iat: now,
    jti: crypto.randomUUID(),
    tenant_id: tenant.id,
    scope: user.scopes
  };
  return jwt.sign(payload, INTERNAL_JWT_SECRET, { algorithm: 'HS256' });
}

// Per-tenant TTL replay cache
class ReplayCache {
  constructor(ttlSeconds = 300) {
    this.cache = new Map();
    this.ttlSeconds = ttlSeconds;
  }

  checkAndStore(tenantId, jti) {
    const key = `${tenantId}:${jti}`;
    if (this.cache.has(key)) return false;
    this.cache.set(key, true);
    setTimeout(() => this.cache.delete(key), this.ttlSeconds * 1000);
    return true;
  }
}

// Middleware: audience check + replay prevention
function authMiddleware(req, res, next) {
  const authHeader = req.headers.authorization;
  if (!authHeader?.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Missing token' });
  }

  const token = authHeader.slice(7);
  let payload;
  try {
    payload = jwt.verify(token, INTERNAL_JWT_SECRET, { algorithms: ['HS256'] });
  } catch (err) {
    return res.status(401).json({ error: 'Invalid token' });
  }

  if (payload.aud !== req.query.service) {
    return res.status(403).json({ error: 'Audience mismatch' });
  }

  if (!replayCache.checkAndStore(payload.tenant_id, payload.jti)) {
    return res.status(403).json({ error: 'Token replay detected' });
  }

  req.user = payload;
  next();
}

// SAML-to-claims adapter
function samlToClaims(samlAssertion) {
  const attributes = samlAssertion.AttributeStatement?.Attribute || [];
  const getAttr = (name) => attributes.find(a => a.Name === name)?.AttributeValue?.[0];

  return {
    id: getAttr('http://schemas.xmlsoap.org/ws/2005/05/identity/claims/nameidentifier'),
    email: getAttr('http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress'),
    tenant: getAttr('tenant-id'),
    scopes: (getAttr('scope') || '').split(' ')
  };
}

// Conformance test endpoint
app.get('/conformance-test', (req, res) => {
  const { token } = req.query;
  if (!token) return res.status(400).json({ valid: false, error: 'Missing token' });

  try {
    const payload = jwt.verify(token, INTERNAL_JWT_SECRET, { algorithms: ['HS256'] });
    res.json({ valid: true, payload });
  } catch (err) {
    res.json({ valid: false, error: err.message });
  }
});
```

