## Code Example
```javascript
// Internal token structure
const INTERNAL_JWT_CLAIMS = ['sub', 'tenant', 'scopes', 'iat', 'exp', 'binding_id'];

// Normalize external token to internal JWT
function normalizeToInternal(token, tokenType, tenantMeta) {
  const mapped = tokenType === 'saml'
    ? mapSamlAttributes(token, tenantMeta.attributeMapping)
    : parseOidcClaims(token);

  return {
    sub: mapped.subject,
    tenant: tenantMeta.tenantId,
    scopes: normalizeScopes(mapped.scopes, tenantMeta.scopeMap),
    iat: Math.floor(Date.now() / 1000),
    exp: Math.floor(Date.now() / 1000) + 3600,
    binding_id: mapped.bindingId || generateBindingId()
  };
}

// RFC 8693 Token Exchange endpoint
async function tokenExchange(req) {
  const { subject_token, subject_token_type, requested_token_type } = req.body;

  // 1. Validate incoming token and extract tenant
  const { token, metadata } = await resolveAndValidate(subject_token);
  const tenantMeta = await tenantCache.get(metadata.tenantId);

  // 2. Run per-tenant validators
  for (const validator of tenantMeta.validators) {
    await validator.validate(token, tenantMeta);
  }

  // 3. Check replay protection
  const jti = computeJti(token);
  if (await replayCache.exists(jti)) {
    throw new ReplayDetectedError(jti);
  }
  await replayCache.add(jti, tenantMeta.replayWindow);

  // 4. Generate internal token
  const internalClaims = normalizeToInternal(token, req.tokenType, tenantMeta);
  const internalToken = signJwt(internalClaims, internalSigningKey);

  // 5. Optionally issue downstream service token (RFC 8693)
  const serviceToken = requested_token_type === 'urn:ietf:params:oauth:token-type:access_token'
    ? signServiceToken({ ...internalClaims, aud: req.audience })
    : internalToken;

  return { access_token: serviceToken, issued_token_type: requested_token_type };
}
```

