## Key Concepts
- **Cross-cache invalidation**: Managing dependencies between caches (profile → timeline)
- **Dependency tracking**: Maintain a graph of cache keys affected by profile changes
- **Redis Streams**: Provides ordered, durable event delivery with at-least-once semantics
- **Idempotent retries**: Use correlation IDs to deduplicate processing
- **Bulk invalidations**: Batch multiple invalidations into single atomic operations

## Code Example
```javascript
// Publisher: emit profile update event
const event = { 
  type: 'PROFILE_UPDATED', 
  userId, 
  correlationId: uuid(), 
  timestamp: Date.now() 
};
await redis.xadd('cache_invalidation', '*', 'event', JSON.stringify(event));

// Consumer: process invalidation with idempotency
const processInvalidation = async (eventId, eventData) => {
  const { userId, correlationId } = JSON.parse(eventData);

  // Idempotency check
  const processed = await redis.set(`processed:${correlationId}`, '1', 'NX', 'EX', 86400);
  if (!processed) return; // Already processed

  // Invalidate profile cache
  await redis.del(`user:${userId}:profile`);

  // Invalidate dependent timeline caches
  const followers = await getFollowers(userId);
  const pipeline = redis.pipeline();
  for (const followerId of followers) {
    pipeline.del(`timeline:${followerId}`);
  }
  await pipeline.exec();

  // Acknowledge processing
  await redis.xack('cache_invalidation', 'invalidation_group', eventId);
};

// Consumer loop
while (true) {
  const result = await redis.xreadgroup(
    'GROUP', 'invalidation_group', 'consumer1',
    'BLOCK', 5000, 'STREAMS', 'cache_invalidation', '>'
  );
  if (result) {
    for (const [stream, events] of result) {
      for (const [eventId, fields] of events) {
        await processInvalidation(eventId, fields[1]);
      }
    }
  }
}
```

