Code Example
```javascript
// getProduct with cache-aside pattern
async function getProduct(tenantId, productId) {
  const cacheKey = `tenant:${tenantId}:product:${productId}`;

  // Check cache first
  let cached = await redis.get(cacheKey);
  if (cached) {
    return JSON.parse(cached);
  }

  // Cache miss - fetch from database
  const product = await db.query(
    'SELECT * FROM products WHERE tenant_id = ? AND id = ?',
    [tenantId, productId]
  );

  if (product) {
    const ttl = product.isHot ? 300 : 60; // 5min hot, 1min cold
    await redis.setex(cacheKey, ttl, JSON.stringify(product));
  } else {
    // Negative caching - cache misses too
    await redis.setex(cacheKey, 30, '');
  }

  return product;
}

// updateProduct with invalidation and stampede protection
async function updateProduct(tenantId, productId, updates) {
  const lockKey = `lock:tenant:${tenantId}:product:${productId}`;
  const cacheKey = `tenant:${tenantId}:product:${productId}`;

  // Acquire distributed lock
  const lock = await redis.set(lockKey, '1', 'NX', 'EX', 10);
  if (!lock) {
    throw new Error('Concurrent update in progress');
  }

  try {
    // Perform database update
    await db.query(
      'UPDATE products SET ? WHERE tenant_id = ? AND id = ?',
      [updates, tenantId, productId]
    );

    // Invalidate cache - delete immediately
    await redis.del(cacheKey);

    // Publish invalidation event for this tenant
    await redis.publish(
      `invalidation:tenant:${tenantId}`,
      JSON.stringify({ productId, action: 'updated' })
    );

  } finally {
    await redis.del(lockKey);
  }
}

// Subscribe to invalidation events
async function subscribeToInvalidations(tenantId) {
  const subscriber = redis.duplicate();
  await subscriber.subscribe(`invalidation:tenant:${tenantId}`);

  subscriber.on('message', async (channel, message) => {
    if (channel === `invalidation:tenant:${tenantId}`) {
      const { productId } = JSON.parse(message);
      console.log(`Invalidated: tenant=${tenantId}, product=${productId}`);
    }
  });
}
```

Key Takeaways
- Always namespace keys by tenant to ensure complete isolation
- Use negative caching to prevent repeated database queries for missing items
- Implement distributed locks on writes to avoid thundering herd on cache miss
- Publish invalidation events for multi-instance deployments to synchronize cache state
- Choose TTLs based on data volatility - hot products get longer TTLs

