A concrete plan for per-tenant cache invalidation in a multi-tenant SaaS environment:

1. **Key Naming Strategy**: Use tenant-scoped keys with a clear hierarchy, such as `tenant:{tenant_id}:cache:{resource}:{entity_id}`. This enables efficient pattern-based scanning and ensures complete isolation between tenants.

2. **Cross-Process Invalidation**: Use Redis Pub/Sub for immediate broadcast invalidation across all application instances. Alternatively, leverage Redis keyspace notifications (`__keyspace@*__`) for event-driven invalidation when keys are modified directly.

3. **TTL with Jitter vs. Explicit Invalidation**: Combine both approaches—set a reasonable base TTL with randomized jitter (±10–20%) to prevent thundering herd problems, but always perform explicit invalidation on upstream writes to guarantee consistency.

4. **Stale Read Detection & Recovery**: Implement versioned keys (include a version or timestamp in the key), use distributed locks for the cache-aside pattern to prevent stampedes, and implement a fallback-to-source strategy with retry logic.

```javascript
// Node.js: Invalidation via Redis Pub/Sub with safe refresh
const redis = require('redis');
const client = redis.createClient();
const subscriber = redis.createClient();

const TENANT_PREFIX = 'tenant';

function buildKey(tenantId, resource, entityId) {
  return `${TENANT_PREFIX}:${tenantId}:cache:${resource}:${entityId}`;
}

function invalidateKey(tenantId, resource, entityId) {
  const key = buildKey(tenantId, resource, entityId);
  client.del(key);
  client.publish(`invalidate:${tenantId}`, JSON.stringify({ resource, entityId }));
}

async function safeRefresh(tenantId, resource, entityId, fetchFn) {
  const key = buildKey(tenantId, resource, entityId);
  const lockKey = `lock:${key}`;

  const lock = await client.set(lockKey, '1', 'NX', 'EX', 10);
  if (!lock) {
    return JSON.parse(await client.get(key));
  }

  try {
    const data = await fetchFn();
    await client.set(key, JSON.stringify(data), 'EX', 300);
    return data;
  } finally {
    await client.del(lockKey);
  }
}

// Subscribe to invalidation events for a specific tenant
subscriber.subscribe(`invalidate:${tenantId}`, (err) => {
  if (err) return console.error('Subscribe error:', err);
});

subscriber.on('message', (channel, message) => {
  const { resource, entityId } = JSON.parse(message);
  const tenantId = channel.split(':')[1];
  client.del(buildKey(tenantId, resource, entityId));
});
```

