  const {tenantId, productId} = event
  const key = `tenant:${tenantId}:product:${productId}`
  await cache.del(key)
  // optionally notify other services or update a stale-flag
}
```
```javascript
// Lock mechanism (pseudo)
function acquireLock(key){
  return cache.set(key + ':lock', '1', {nx: true, px: 3000})
}
function releaseLock(key){
  return cache.del(key + ':lock')
}
```

