## Code Example

```javascript
// Minimal orchestrator sketch
class SagaOrchestrator {
  constructor(store) { this.store = store }
  startSaga(id) { this.store.appendEvent(id, 'DraftCreated', {}) }
  onEvent(e) {
    switch(e.type){
      case 'LicenseReserved':
        this.store.appendEvent(e.id, 'PaymentRequested', {})
        break;
      case 'PaymentProcessed':
        this.store.appendEvent(e.id, 'PublishRequested', {})
        break;
      case 'PaymentFailed':
      case 'LicenseReservationFailed':
        this.compensate(e.id)
        break;
    }
  }
  compensate(id){
    this.store.appendEvent(id, 'CancelDraft', {})
  }
}
```

