```javascript
// Data contracts
class OrderPlaced { constructor(orderId, items, amount) { this.orderId = orderId; this.items = items; this.amount = amount; } }
class InventoryReserved { constructor(orderId) { this.orderId = orderId; } }
class PaymentAuthorized { constructor(orderId) { this.orderId = orderId; } }
class PaymentFailed { constructor(orderId, reason) { this.orderId = orderId; this.reason = reason; } }
class InventoryRejected { constructor(orderId, reason) { this.orderId = orderId; this.reason = reason; } }

// Append-only EventStore per order
class EventStore {
  constructor() { this.events = new Map(); }
  append(orderId, event) {
    if (!this.events.has(orderId)) this.events.set(orderId, []);
    this.events.get(orderId).push(event);
  }
  getEvents(orderId) { return this.events.get(orderId) || []; }
}

// Saga Orchestrator
class OrderSaga {
  constructor(eventStore, inventoryService, paymentService) {
    this.eventStore = eventStore;
    this.inventory = inventoryService;
    this.payment = paymentService;
  }
  async handle(event) {
    if (event instanceof OrderPlaced) {
      this.eventStore.append(event.orderId, event);
      const inventoryResult = await this.inventory.reserve(event.orderId, event.items);
      if (inventoryResult.success) {
        this.eventStore.append(event.orderId, new InventoryReserved(event.orderId));
        const paymentResult = await this.payment.authorize(event.orderId, event.amount);
        if (paymentResult.success) {
          this.eventStore.append(event.orderId, new PaymentAuthorized(event.orderId));
        } else {
          this.eventStore.append(event.orderId, new PaymentFailed(event.orderId, paymentResult.reason));
          this.compensate(event.orderId);
        }
      } else {
        this.eventStore.append(event.orderId, new InventoryRejected(event.orderId, inventoryResult.reason));
      }
    }
  }
  compensate(orderId) {
    const events = this.eventStore.getEvents(orderId);
    events.reverse().forEach(event => {
      if (event instanceof InventoryReserved) {
        this.inventory.release(orderId);
      }
    });
  }
}

// Read Model Projection
class OrderStatusProjection {
  constructor(eventStore) {
    this.eventStore = eventStore;
    this.orderStatus = new Map();
  }
  project(orderId) {
    const events = this.eventStore.getEvents(orderId);
    let status = 'Pending';
    events.forEach(event => {
      if (event instanceof PaymentAuthorized) status = 'Completed';
      else if (event instanceof PaymentFailed || event instanceof InventoryRejected) status = 'Failed';
    });
    this.orderStatus.set(orderId, status);
    return status;
  }
}
```

