class RefundOrchestrator {
  constructor(outboxStore, tenantConfig) {
    this.outbox = outboxStore;
    this.config = tenantConfig;
  }

  async start(orderId, tenantId) {
    const tenant = this.config.get(tenantId);
    await this.outbox.append({
      type: 'RefundCommand',
      orderId,
      tenantId,
      maxRetries: tenant.maxRefundRetries,
      timeoutMs: tenant.refundTimeoutMs
    });
  }

  async onRefundResult(evt) {
    if (evt.status === 'success') {
      await this.completeOrder(evt.orderId, evt.tenantId);
    } else {
      await this.triggerCompensation(evt.orderId, evt.tenantId);
    }
  }

  async triggerCompensation(orderId, tenantId) {
    const tenant = this.config.get(tenantId);
    if (tenant.refundRetries >= tenant.maxRefundRetries) {
      await this.outbox.append({
        type: 'CompensatingTransaction',
        orderId,
        tenantId,
        action: 'VOID_PAYMENT'
