// Idempotent event append with cross-region merge
async function appendEvent(event) {
  const globalSeq = await sequencer.nextTimestamp();
  const idempotencyKey = `${event.user_id}:${globalSeq}:${event.event_type}`;

  // Check for duplicates
  if (await cache.exists(idempotencyKey)) {
    return { status: 'duplicate', seq: globalSeq };
  }

  // Write to local region with Raft quorum
  const writeResult = await raftGroup.write({
    key: `shard_${hash(event.user_id)}`,
    value: { ...event, global_seq: globalSeq, idempotency_key: idempotencyKey }
  });

  // Async replication to other regions
  await replicateCrossRegion(event, writeResult.quorumAck);

  return { status: 'success', seq: globalSeq };
}

// Cross-region merge for reads
async function readUserEvents(userId, region) {
  const localEvents = await readRegion(userId, region);
  const remoteEvents = await Promise.all(
    otherRegions.map(r => readRegion(userId, r))
  );

  // Merge by global_seq, deduplicate by idempotency_key
  return mergeByTimestamp([...localEvents, ...remoteEvents], 'global_seq');
}
